document.addEventListener("DOMContentLoaded",()=>{const d=document.getElementById("downloadBtn"),u=document.getElementById("threadsUrl"),s=document.getElementById("statusMessage"),r=document.getElementById("resultSection"),p=document.getElementById("previewContainer"),f=document.getElementById("finalDownloadBtn"),links=document.querySelectorAll(".menu-link,.desktop-menu-link");const show=(m,e=false)=>{if(!s)return;s.textContent=m;s.className=`mt-4 text-sm ${e?"text-red-500":"text-white"}`;s.classList.remove("hidden")};const hide=()=>{if(s)s.classList.add("hidden")};if(d&&u&&s&&r&&p&&f){d.addEventListener("click",async()=>{const url=u.value.trim();if(!url){show("Please enter a Threads URL",true);return}if(!url.includes("threads.net")&&!url.includes("threads.com")){show("Invalid Threads URL. Please check again.",true);return}hide();r.classList.add("hidden");d.disabled=true;d.textContent="Processing...";try{const res=await fetch(`https://dt.romitkr361.workers.dev/?url=${encodeURIComponent(url)}`);const data=await res.json();if(data.success){let media=[];if(data.media&&Array.isArray(data.media))media=data.media;else if(data.url&&data.type)media=[{url:data.url,type:data.type}];if(media.length===0){show("No media found on this page.",true);return}p.innerHTML="";p.className="grid grid-cols-1 gap-6 p-4";const downloadItem=async(item,i)=>{try{let blob;if(item.type!=="video"){const pr=`https://images.weserv.nl/?url=${encodeURIComponent(item.url)}&output=bin`;const b=await fetch(pr);blob=await b.blob()}else{const b=await fetch(item.url);blob=await b.blob()}const urlBlob=URL.createObjectURL(blob);const a=document.createElement("a");a.href=urlBlob;a.download=`threads-${item.type}-${Date.now()}-${i}.${item.type==="video"?"mp4":"jpg"}`;document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(urlBlob)}catch(e){window.open(item.url,"_blank")}};media.forEach((item,i)=>{const wrap=document.createElement("div");wrap.className="bg-black/90 p-4 rounded-xl border border-white/20 flex flex-col items-center text-white shadow-2xl";if(item.type==="video"){const v=document.createElement("video");v.controls=true;v.className="rounded-lg shadow-sm w-full max-h-[400px] bg-black mb-4";const src=document.createElement("source");src.src=item.url;src.type="video/mp4";v.appendChild(src);wrap.appendChild(v)}else{const img=document.createElement("img");img.src=`https://images.weserv.nl/?url=${encodeURIComponent(item.url)}`;img.className="rounded-lg shadow-sm w-full max-h-[400px] object-contain mb-4";wrap.appendChild(img)}const b=document.createElement("button");b.className="w-full bg-black text-white px-6 py-3 rounded-lg font-bold hover:bg-[#111] transition-all";b.textContent=`Download ${item.type==="video"?"Video":"Image"} ${media.length>1?i+1:""}`;b.onclick=async()=>{b.textContent="Downloading...";b.disabled=true;await downloadItem(item,i+1);b.textContent="Download";b.disabled=false};wrap.appendChild(b);p.appendChild(wrap)});f.classList.add("hidden");r.classList.remove("hidden");r.scrollIntoView({behavior:"smooth"})}else show(data.error||"Failed to extract media.",true)}catch(e){show("An error occurred while processing your request.",true)}finally{d.disabled=false;d.textContent="Download"}});u.addEventListener("keypress",e=>{if(e.key==="Enter")d.click()})}let path=window.location.pathname;if(path.endsWith("/index.html"))path=path.replace("/index.html","/");if(path!=="/"&&path.endsWith("/"))path=path.slice(0,-1);links.forEach(l=>{let h=l.getAttribute("href");if(h.endsWith("/index.html"))h=h.replace("/index.html","/");if(h!=="/"&&h.endsWith("/"))h=h.slice(0,-1);if(h===path||(path==="/"&&h==="/"))l.classList.add("active")})});